        string start1 = event1[0], end1 = event1[1];
        string start2 = event2[0], end2 = event2[1];

        int start1h = stoi(start1.substr(0, 2)), start1m = stoi(start1.substr(3));
        int end1h = stoi(end1.substr(0, 2)), end1m = stoi(end1.substr(3));
